package com.multilanglearner.domain.util

import com.multilanglearner.domain.model.WordTimestamp

/**
 * Word-level timestamp alignment - ported from main.js generate-subtitle handler.
 * Matches displayed words to API word timestamps using fuzzy matching.
 */
object WordAligner {
    private val CLEAN_REGEX = Regex("[^\\p{L}\\p{M}\\p{N}'-]")

    /**
     * Find word timestamps for the current subtitle cue.
     * Filters wordTimings to those within the cue's time range,
     * then maps displayed words to API words via fuzzy match.
     */
    fun alignWords(
        displayedWords: List<String>,
        allTimings: List<WordTimestamp>,
        cueStartSec: Double,
        cueEndSec: Double
    ): List<WordTimestamp?> {
        val subWords = allTimings.filter { it.s >= cueStartSec - 0.1 && it.s <= cueEndSec + 0.3 }
        if (subWords.isEmpty()) return List(displayedWords.size) { null }

        val result = mutableListOf<WordTimestamp?>()
        var wtIdx = 0
        for (dw in displayedWords) {
            val clean = dw.trim().lowercase().replace(CLEAN_REGEX, "")
            var matched: WordTimestamp? = null
            for (k in wtIdx until subWords.size) {
                val wtWord = subWords[k].w.trim().lowercase().replace(CLEAN_REGEX, "")
                if (wtWord == clean || clean.startsWith(wtWord) || wtWord.startsWith(clean)) {
                    matched = subWords[k]
                    wtIdx = k + 1
                    break
                }
            }
            result.add(matched)
        }
        return result
    }
}
